/** A condition to be used against `Burn` object types. All fields are tested for equality and combined with a logical ‘and.’ */
export type BurnCondition = {
  /** Checks for equality with the object’s `boostAmount` field. */
  boostAmount?: InputMaybe<Scalars['BigFloat']['input']>;
  /** Checks for equality with the object’s `eventId` field. */
  eventId?: InputMaybe<Scalars['BigInt']['input']>;
  /** Checks for equality with the object’s `id` field. */
  id?: InputMaybe<Scalars['Int']['input']>;
  /** Checks for equality with the object’s `timestamp` field. */
  timestamp?: InputMaybe<Scalars['Datetime']['input']>;
  /** Checks for equality with the object’s `totalAmount` field. */
  totalAmount?: InputMaybe<Scalars['BigFloat']['input']>;
  /** Checks for equality with the object’s `valueUsd` field. */
  valueUsd?: InputMaybe<Scalars['BigFloat']['input']>;
};

/** A filter to be used against `Burn` object types. All fields are combined with a logical ‘and.’ */
export type BurnFilter = {
  /** Checks for all expressions in this list. */
  and?: InputMaybe<Array<BurnFilter>>;
  /** Filter by the object’s `boostAmount` field. */
  boostAmount?: InputMaybe<BigFloatFilter>;
  /** Filter by the object’s `eventId` field. */
  eventId?: InputMaybe<BigIntFilter>;
  /** Filter by the object’s `id` field. */
  id?: InputMaybe<IntFilter>;
  /** Negates the expression. */
  not?: InputMaybe<BurnFilter>;
  /** Checks for any expressions in this list. */
  or?: InputMaybe<Array<BurnFilter>>;
  /** Filter by the object’s `timestamp` field. */
  timestamp?: InputMaybe<DatetimeFilter>;
  /** Filter by the object’s `totalAmount` field. */
  totalAmount?: InputMaybe<BigFloatFilter>;
  /** Filter by the object’s `valueUsd` field. */
  valueUsd?: InputMaybe<BigFloatFilter>;
};

