export type SwapRequestType =
  | 'INGRESS_EGRESS_FEE'
  | 'LEGACY_CCM'
  | 'LEGACY_INTERNAL_SWAP'
  | 'LEGACY_SWAP'
  | 'NETWORK_FEE'
  | 'ON_CHAIN'
  | 'REGULAR';

/** A filter to be used against SwapRequestType fields. All fields are combined with a logical ‘and.’ */
export type SwapRequestTypeFilter = {
  /** Not equal to the specified value, treating null like an ordinary value. */
  distinctFrom?: InputMaybe<SwapRequestType>;
  /** Equal to the specified value. */
  equalTo?: InputMaybe<SwapRequestType>;
  /** Greater than the specified value. */
  greaterThan?: InputMaybe<SwapRequestType>;
  /** Greater than or equal to the specified value. */
  greaterThanOrEqualTo?: InputMaybe<SwapRequestType>;
  /** Included in the specified list. */
  in?: InputMaybe<Array<SwapRequestType>>;
  /** Is null (if `true` is specified) or is not null (if `false` is specified). */
  isNull?: InputMaybe<Scalars['Boolean']['input']>;
  /** Less than the specified value. */
  lessThan?: InputMaybe<SwapRequestType>;
  /** Less than or equal to the specified value. */
  lessThanOrEqualTo?: InputMaybe<SwapRequestType>;
  /** Equal to the specified value, treating null like an ordinary value. */
  notDistinctFrom?: InputMaybe<SwapRequestType>;
  /** Not equal to the specified value. */
  notEqualTo?: InputMaybe<SwapRequestType>;
  /** Not included in the specified list. */
  notIn?: InputMaybe<Array<SwapRequestType>>;
};

